+                    Some(&uint64_kwargs),
+                )?,
+                &theirs_uint64.call_method(
+                    "randint",
+                    (0_i64, 1_000_000_i64, shape),
+                    Some(&uint64_kwargs),
+                )?,
+            )?;
+
+            Ok(())
+        });
+    }
